import React, {useState, useEffect} from "react";
import "./timelistCSS.css";
import {  } from "react-router-dom";

const TimeList = () => {
    var showTimes = {
        '01': {
            year: "2023",
            month: "11",
            day: "20",
            week: "一",
            times: ['18:05']
        },
        '02': {
            year: "2023",
            month: "11",
            day: "21",
            week: "二",
            times: ['13:20', '18:05']
        },
        '03': {
            year: "2023",
            month: "11",
            day: "22",
            week: "三",
            times: ['13:20', '18:05']
        },
    }

    return(
        <>
            {index % 2 === 0 ? (
                <div className="movieDay">
                    {Object.keys(showTimes).map((key) => (
                        <div key={key}>
                        <h3>
                            {showTimes[key].year}年{showTimes[key].month}月
                            {showTimes[key].day}日 星期{showTimes[key].week}
                        </h3>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="timeSeat">
                    {Object.keys(showTimes).map((key) => (
                        <div key={key}>
                            {Object.keys(showTimes[key].times).map((key1) => (
                                <p key={key1}> {showTimes[key].times[key1]} </p>
                            ))}
                        </div>
                    ))}
                </div>
            )}
        </>
    );
}

export default TimeList;
